var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"18:10 ARC-KP1\\n어느 사무실\\n<color=#ff3636>두 번째 사건 발생</color> 1시간 경과","JPN":"18:10 ARC-KP1\\nとある事務所\\n<color=#ff3636>二度目の事件発生から</color>1時間経過","ENG":"[[","TWN":"18:10 ARC-KP1\\n某間辦公室\\n<color=#ff3636>第二起事件發生</color>經過1小時","THA":"18.10 น. ARC-KP1\\nสำนักงานไม่ทราบชื่อ\\n1 ชั่วโมงหลัง<color=#ff3636>เหตุการณ์ที่ 2</color>","VTN":"18:10 ARC-KP1\\nVăn Phòng Không Xác Định\\n1 giờ sau <color=#ff3636>sự cố thứ 2</color>","SCN":"18:10 ARC-KP1\\n某个办公室\\n<color=#ff3636>第二起事件发生</color>经过1小时","DEU":"18:10 Uhr ARC-KP1 \\nEin Büro\\n1 Stunde nach dem <color=#ff3636>2. Ereignis</color>","FRA":"18h10 ARC-KP1\\nDans un bureau\\n1 heure après le <color=#ff3636>deuxième incident</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"메카닉스 대표, 그 돼지 자식을 해치웠다고 보고 받았어요.","JPN":"メカニックス代表、あのブタ野郎を始末したと報告を受けました。","ENG":"I’ve just received word that the pig, the CEO of Mechanics, has been dealt with.","TWN":"我收到消息，說已經把機械代表那個豬八戒處理掉了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"이야~ 고모가 선물해 준 그거 일 처리 확실하던데요.","JPN":"いやー、叔母さんが贈ってくれたアレ、有能でしたよ。","ENG":"That thing you gave me sure did the trick.","TWN":"哇～姑姑送我的那個禮物，做事情很俐落呢！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"추가로 발주할 생각은 없어요? 돈은 고모 원하는 대로 꽂아 드릴 테니까.","JPN":"追加で発注するのはどうですか？　金なら叔母さんが欲しいだけ渡しますよ。","ENG":"Any plans to make more of them? I’ll pay however much you want, Auntie.","TWN":"姑姑不打算再多做幾個嗎？錢的事不用擔心，姑姑想要多少，我都會給姑姑弄來。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"흐음, 우리 조카님 부탁인데 못 해 줄 것도 없지.","JPN":"まあ、うちの甥っ子の頼みなら聞いてあげないとね。","ENG":"Hmm, well I can’t decline my nephew’s request, can I?","TWN":"呵呵，姪子的要求，姑姑怎麼能拒絕呢？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"이 고모가 시키는 대로만 잘 하면 말이야.","JPN":"もちろん、この叔母さんの言うとおりにしてくれたら、だけど。","ENG":"As long as you do as you’re told.","TWN":"但前提是你要乖乖聽姑姑的話。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"걱정하지 마요, 고모. 다음 타겟도 깔끔하게 처리할 테니까.","JPN":"心配しないでください、叔母さん。\\n次のターゲットも手っ取り早く処理しますから。","ENG":"No need to be concerned, Auntie. The next target will also be a clean hit.","TWN":"姑姑請放心，下一個目標也會處理乾淨的！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"<color=#ffd34c>그것</color>만 있으면……. 식은 죽 먹기죠.","JPN":"<color=#ffd34c>アレ</color>さえあれば……朝飯前ですよ。","ENG":"It’s a piece of cake... if we have that <color=#ffd34c>thing</color>.","TWN":"只要有<color=#ffd34c>那個</color>……根本是輕而易舉！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"19:22 ARC-KP1\\n알파트릭스 본사 회의실\\n<color=#ff3636>두 번째 사건 발생</color> 2시간 경과","JPN":"19:22 ARC-KP1\\nアルファトリックス本社会議室\\n<color=#ff3636>二度目の事件発生から</color>2時間経過","ENG":"[[","TWN":"19:22 ARC-KP1\\n阿爾法崔克斯總公司會議室\\n<color=#ff3636>第二波事件發生</color>後經過2小時","THA":"19.22 น. ARC-KP1\\nห้องประชุมสำนักงานใหญ่อัลฟาทริกซ์\\n2 ชั่วโมงหลังจาก<color=#ff3636>เหตุการณ์ที่ 2</color>","VTN":"19:22 ARC-KP1\\nPhòng Họp Tổng Bộ Alphatrix\\n2 giờ sau <color=#ff3636>sự cố thứ 2</color>","SCN":"19:22 ARC-KP1\\n阿尔法崔克斯总公司会议室\\n<color=#ff3636>第二起事件发生</color>经过2小时","DEU":"[[","FRA":"19h22 ARC-KP1\\nSalle de réunion du QG d'Alphatrix\\n2 heures après le <color=#ff3636>deuxième incident</color>"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"부회장이 살해당하고 채 하루도 지나지 않았습니다!","JPN":"副会長が殺害されてから一日も経っていません！","ENG":"Not even a day has passed since the assassination of the Vice Chairman!","TWN":"副會長遭人殺害都還不到一天！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"그런데 이번엔 메카닉스 대표라니요? 이게 말이나 됩니까?","JPN":"なのに今度はメカニックス代表ですと？　あり得ない！","ENG":"But now, even the CEO of Mechanics? This is preposterous!","TWN":"這次是機械代表遇害？這是怎麼搞的？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"여기 계신 분들의 도움으로 부회장 건이 외부에 알려지는 것은 잠시 막았습니다만…….","JPN":"ここにいらっしゃる皆様の協力のもと、\\n副会長の件が外部に知られることはしばらく防げましたが……","ENG":"We were able to keep the media quiet about our Vice Chairman’s death...","TWN":"副會長的事，是靠在座大家的幫忙，好不容易才壓下來，沒有讓消息走漏出去……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"메카닉스 대표까지 그렇게 된 이상 사건을 감추는 데에도 한계가 있어요.","JPN":"メカニックス代表までああなった以上、事件を隠すにも限界があります。","ENG":"However, with the CEO of Mechanics also being found dead, it's only a matter of time before this becomes public.","TWN":"現在連機械代表都發生這種事，要封鎖消息恐怕會有困難。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"위기대응 부서를 설득해서라도 어서 신지아를 잡아야 합니다.","JPN":"危機管理部を説得してでも、一刻も早くヒメノ・ユイを\\n捕まえなければなりません。","ENG":"We need to get the Crisis Response Department to capture Shin Jia, ASAP.","TWN":"就算要說服危機處理小組，也必須盡快抓到沈佳。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"이 사건이 알려지면 주가 폭락은 둘째 쳐도, 회장 선임에도 악영향이 갈 수 있어요.","JPN":"この事件が知られれば、株価暴落はもちろん、会長選任にも\\n悪影響を与えるでしょう。","ENG":"If word gets out, not only will the stock prices plummet, it will also negatively impact the appointment of our new President.","TWN":"這件事要是曝光，不要說股價會暴跌，更重要的是，對於選出新任會長會有不好的影響。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};